import React from "react"
import Select from 'react-select'
import { properties } from '../../properties/properties.js'
import querystring from 'query-string'

class GetUser extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, usersResult: [], selectedValue: "", lastSortColumn: "", lastSortOrder: 0, selectedDeptValue: "", selectedDivisionValue: "",
            selectedSubDivisionValue: "", selectedTeam: ""
        };
    }


   groupBy(key, array) {
      var result = [];
      for (var i = 0; i < array.length; i++) {
        var added = false;
        for (var j = 0; j < result.length; j++) {
          if (result[j][key] == array[i][key]) {
            result[j].items.push(array[i]);
            added = true;
            break;
          }
        }
        if (!added) {
          var entry = {items: []};
          entry[key] = array[i][key];
          entry.items.push(array[i]);
          result.push(entry);
        }
      }
      return result;
  }


    handleOnClickColumn = (column) => {
      console.log(column)

      var lastSortOrder = this.state.lastSortOrder

      if (column === this.state.lastSortColumn) {
        if (lastSortOrder === 0) {
          lastSortOrder = 1
        } else {
          lastSortOrder = 0
        }
      } else {
        lastSortOrder = 0
      }

      var results = this.state.results

      if (lastSortOrder === 0) {
        results.sort(function(a,b) {
          var x = a[column].toLowerCase();
          var y = b[column].toLowerCase();
          return x < y ? -1 : x > y  ? 1: 0;
        })
      } else {
        results.sort(function(a,b) {
          var x = a[column].toLowerCase();
          var y = b[column].toLowerCase();
          return y < x ? -1 : y > x  ? 1: 0;
        })
      }




      //console.log(results)
      this.setState({lastSortColumn: column})
      this.setState({lastSortOrder: lastSortOrder})
      this.setState({results: results})

    }


    handleSelectChange = (selectedOptions) => {

        this.setState({screen: 0})
        this.setState({selectedValue: selectedOptions.value})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `voalte2?name=` + selectedOptions.value, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({usersResult: response.building})

            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });



      }




      componentDidMount() {



        var building = querystring.parse(window.location.search);

        var buildingName = "Providers Adult"
        if (building.building === "PA") {
          buildingName = "Providers Adult"
        }
        if (building.building === "PPOak") {
          buildingName = "Providers Pediatrics BCH Oak"
        }
        if (building.building === "PPSF") {
          buildingName = "Providers Pediatrics BCH SF"
        }
        if (building.building === "PPA") {
          buildingName = "Providers Periop/Anesthesia"
        }
        if (building.building === "PR") {
          buildingName = "Providers Radiology"
        }
