                    </td><td style={{border: "1px solid", padding: "5px"}}>
                      <button type="button" onClick={data => this.handleOnClickColumn("last_name")}>Last Name</button>&nbsp;{col2}
                    </td><td style={{border: "1px solid", padding: "5px"}}>
                      <button type="button" onClick={data => this.handleOnClickColumn("first_name")}>First Name</button>&nbsp;{col3}
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                      Extension
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                      DID
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                      Last login
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                      Phone
                    </td>
                    </tr>)


                    tableContent.map(rec4 => {
                        tableContentformat.push(rec4)
                    })


                }
                content.push(<table style={{marginTop: "5px"}}>{tableContentformat}</table>)

              }




          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><div>{header}</div>{content}</div>

            );
          }


  };

  export default GetUser
